-- Upgrade default LocateFlow transactional email templates and add a
-- contract reminder template so logged sends can be tied to a template row.

SET @welcome_body = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><meta name="color-scheme" content="light dark"><meta name="supported-color-schemes" content="light dark"><title>Welcome to LocateFlow</title></head><body style="margin:0;padding:0;background:#f5f7fb;font-family:Arial,Helvetica,sans-serif;color:#172033;"><div style="display:none;max-height:0;overflow:hidden;opacity:0;color:transparent;">Your LocateFlow account is ready.</div><table role="presentation" width="100%" cellspacing="0" cellpadding="0" border="0" bgcolor="#f5f7fb" style="border-collapse:collapse;background:#f5f7fb;"><tr><td align="center" style="padding:24px 12px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" border="0" style="width:100%;max-width:600px;border-collapse:collapse;"><tr><td style="padding:0 0 12px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="border-collapse:collapse;"><tr><td bgcolor="#f97316" style="width:34px;height:34px;border-radius:8px;text-align:center;color:#ffffff;font-weight:700;font-size:13px;line-height:34px;">LF</td><td style="padding-left:10px;font-size:20px;line-height:24px;font-weight:700;color:#172033;">LocateFlow</td></tr></table></td></tr><tr><td bgcolor="#ffffff" style="background:#ffffff;border:1px solid #d9e1ea;border-radius:8px;padding:32px 28px;"><h1 style="margin:0 0 16px;font-size:24px;line-height:31px;color:#172033;font-weight:700;">Welcome to LocateFlow</h1><p style="margin:0 0 14px;font-size:15px;line-height:24px;color:#172033;">Hi <strong>{{firstName}}</strong>,</p><p style="margin:0 0 14px;font-size:15px;line-height:24px;color:#172033;">Welcome to LocateFlow. You can now organize addresses, services, reminders, and moving tasks in one place.</p><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="border-collapse:collapse;margin:24px 0 8px;"><tr><td bgcolor="#f97316" style="border-radius:6px;"><a href="{{dashboardLink}}" style="display:inline-block;padding:13px 20px;font-size:15px;line-height:18px;color:#ffffff;text-decoration:none;font-weight:700;border-radius:6px;">Open Dashboard</a></td></tr></table></td></tr><tr><td style="padding:18px 4px 0;text-align:left;"><p style="margin:0 0 6px;font-size:12px;line-height:18px;color:#5f6b7a;font-weight:700;">LocateFlow</p><p style="margin:0 0 6px;font-size:12px;line-height:18px;color:#5f6b7a;"><a href="https://locateflow.com" style="color:#c2410c;text-decoration:underline;">https://locateflow.com</a>&nbsp;|&nbsp;<a href="mailto:support@locateflow.com" style="color:#c2410c;text-decoration:underline;">support@locateflow.com</a></p><p style="margin:0;font-size:12px;line-height:18px;color:#5f6b7a;">You&#39;re receiving this email because you used LocateFlow.</p></td></tr></table></td></tr></table></body></html>';
INSERT INTO `EmailTemplate` (`id`, `slug`, `name`, `subject`, `body`, `category`, `variables`, `isActive`, `isDefault`, `createdAt`, `updatedAt`)
VALUES (CONCAT('tpl_', LEFT(REPLACE(UUID(), '-', ''), 22)), 'welcome', 'Welcome Email', 'Welcome to LocateFlow', @welcome_body, 'TRANSACTIONAL', '["firstName","dashboardLink","appUrl"]', true, true, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3))
