SET @reset_body = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><meta name="color-scheme" content="light dark"><meta name="supported-color-schemes" content="light dark"><title>Reset your password</title></head><body style="margin:0;padding:0;background:#f5f7fb;font-family:Arial,Helvetica,sans-serif;color:#172033;"><div style="display:none;max-height:0;overflow:hidden;opacity:0;color:transparent;">Use this secure link to reset your LocateFlow password.</div><table role="presentation" width="100%" cellspacing="0" cellpadding="0" border="0" bgcolor="#f5f7fb" style="border-collapse:collapse;background:#f5f7fb;"><tr><td align="center" style="padding:24px 12px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" border="0" style="width:100%;max-width:600px;border-collapse:collapse;"><tr><td style="padding:0 0 12px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="border-collapse:collapse;"><tr><td bgcolor="#f97316" style="width:34px;height:34px;border-radius:8px;text-align:center;color:#ffffff;font-weight:700;font-size:13px;line-height:34px;">LF</td><td style="padding-left:10px;font-size:20px;line-height:24px;font-weight:700;color:#172033;">LocateFlow</td></tr></table></td></tr><tr><td bgcolor="#ffffff" style="background:#ffffff;border:1px solid #d9e1ea;border-radius:8px;padding:32px 28px;"><h1 style="margin:0 0 16px;font-size:24px;line-height:31px;color:#172033;font-weight:700;">Reset your password</h1><p style="margin:0 0 14px;font-size:15px;line-height:24px;color:#172033;">Hi <strong>{{firstName}}</strong>,</p><p style="margin:0 0 14px;font-size:15px;line-height:24px;color:#172033;">We received a request to reset your LocateFlow password.</p><p style="margin:16px 0 0;font-size:13px;line-height:20px;color:#5f6b7a;">This link expires in 1 hour and can only be used once.</p><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="border-collapse:collapse;margin:24px 0 8px;"><tr><td bgcolor="#f97316" style="border-radius:6px;"><a href="{{resetLink}}" style="display:inline-block;padding:13px 20px;font-size:15px;line-height:18px;color:#ffffff;text-decoration:none;font-weight:700;border-radius:6px;">Reset Password</a></td></tr></table><p style="margin:16px 0 0;font-size:13px;line-height:20px;color:#5f6b7a;">If this was not you, ignore this email or contact support.</p></td></tr><tr><td style="padding:18px 4px 0;text-align:left;"><p style="margin:0 0 6px;font-size:12px;line-height:18px;color:#5f6b7a;font-weight:700;">LocateFlow</p><p style="margin:0 0 6px;font-size:12px;line-height:18px;color:#5f6b7a;"><a href="https://locateflow.com" style="color:#c2410c;text-decoration:underline;">https://locateflow.com</a>&nbsp;|&nbsp;<a href="mailto:support@locateflow.com" style="color:#c2410c;text-decoration:underline;">support@locateflow.com</a></p><p style="margin:0;font-size:12px;line-height:18px;color:#5f6b7a;">You&#39;re receiving this email because you used LocateFlow.</p></td></tr></table></td></tr></table></body></html>';
