SET @upgrade_body = REPLACE(@upgrade_body, 'Your LocateFlow trial expires in <strong>{{daysLeft}} days</strong>. Review your subscription settings to choose what happens next.', 'Your LocateFlow plan was updated to <strong>{{planName}}</strong>. You can review your current billing details from account settings.');
SET @upgrade_body = REPLACE(@upgrade_body, 'In {{daysLeft}} days', '{{planName}}');
SET @upgrade_body = REPLACE(@upgrade_body, 'Trial ends', 'Plan');
SET @upgrade_body = REPLACE(@upgrade_body, '{{upgradeLink}}', '{{appUrl}}/settings/subscription');
