VALUES (CONCAT('tpl_', LEFT(REPLACE(UUID(), '-', ''), 22)), 'subscription-upgrade', 'Plan Updated', 'Your LocateFlow plan was updated', @upgrade_body, 'TRANSACTIONAL', '["firstName","planName","appUrl"]', true, true, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3))
