SET @approved_body = REPLACE(@bill_body, 'Bill reminder', 'Review approved');
SET @approved_body = REPLACE(@approved_body, 'Your <strong>{{serviceName}}</strong> bill is due in <strong>{{daysLeft}} days</strong>.', 'Your review for <strong>{{providerName}}</strong> was approved. Thank you for sharing your experience with other LocateFlow users.');
SET @approved_body = REPLACE(@approved_body, '<tr><td style="padding:10px 0;color:#5f6b7a;">Service</td><td align="right" style="padding:10px 0;font-weight:700;">{{serviceName}}</td></tr><tr><td style="padding:10px 0;color:#5f6b7a;">Amount</td><td align="right" style="padding:10px 0;font-weight:700;">${{amount}}</td></tr><tr><td style="padding:10px 0;color:#5f6b7a;">Due Date</td><td align="right" style="padding:10px 0;font-weight:700;">{{dueDate}}</td></tr>', '<tr><td style="padding:10px 0;color:#5f6b7a;">Provider</td><td align="right" style="padding:10px 0;font-weight:700;">{{providerName}}</td></tr>');
SET @approved_body = REPLACE(@approved_body, '{{appUrl}}/services', '{{appUrl}}/community');
SET @approved_body = REPLACE(@approved_body, 'View Services', 'View Reviews');
